class HogQLQueryModifiers(BaseModel):
    model_config = ConfigDict(
        extra="forbid",
    )
    bounceRateDurationSeconds: float | None = None
    bounceRatePageViewMode: BounceRatePageViewMode | None = None
    convertToProjectTimezone: bool | None = None
    customChannelTypeRules: list[CustomChannelRule] | None = None
    dataWarehouseEventsModifiers: list[DataWarehouseEventsModifier] | None = None
    debug: bool | None = None
    forceClickhouseDataSkippingIndexes: list[str] | None = Field(
        default=None,
        description=("If these are provided, the query will fail if these skip indexes are not used"),
    )
    formatCsvAllowDoubleQuotes: bool | None = None
    inCohortVia: InCohortVia | None = None
    inlineCohortCalculation: InlineCohortCalculation | None = None
    materializationMode: MaterializationMode | None = None
    materializedColumnsOptimizationMode: MaterializedColumnsOptimizationMode | None = None
    optimizeJoinedFilters: bool | None = None
    optimizeProjections: bool | None = None
    parserMode: ParserMode | None = Field(
        default=None,
        description=(
            "HogQL parser backend; absent → `rust_py_with_cpp_shadow` (rust-py is"
            " primary, cpp runs as a sampled shadow). `*_shadow` modes return the"
            " primary result and sample-compare against the other parser, reporting"
            " divergences without failing the request. The `rust_py_*` modes drive the"
            " same hand-rolled Rust parser as `rust_*` but build `posthog.hogql.ast`"
            " dataclass instances directly via PyO3, skipping the JSON round-trip."
        ),
    )
    personsArgMaxVersion: PersonsArgMaxVersion | None = None
    personsJoinMode: PersonsJoinMode | None = None
    personsOnEventsMode: PersonsOnEventsMode | None = None
    propertyGroupsMode: PropertyGroupsMode | None = None
    pushDownPredicates: bool | None = None
    s3TableUseInvalidColumns: bool | None = None
    sessionIdPushdown: bool | None = Field(
        default=None,
        description=(
            "Push a `session_id_v7 IN (SELECT … FROM events WHERE …)` predicate into"
            " the raw_sessions subquery to limit aggregation to sessions that"
            " participate in the outer events filter."
        ),
    )
    sessionPropertyPreAggregation: bool | None = Field(
        default=None,
        description=(
            "Pre-filter raw_sessions aggregation by `session_id_v7 IN (cheap"
            " pre-aggregation that only materializes the columns referenced by the"
            " outer-WHERE session predicate)`. Useful when the breakdown/SELECT pulls"
            " in many session columns (e.g. `$channel_type`) but the filter only"
            " references one (e.g. `$entry_current_url`)."
        ),
    )
    sessionTableVersion: SessionTableVersion | None = None
    sessionsV2JoinMode: SessionsV2JoinMode | None = None
    timings: bool | None = None
    useMaterializedViews: bool | None = None
    usePreaggregatedIntermediateResults: bool | None = None
    usePreaggregatedTableTransforms: bool | None = Field(
        default=None,
        description=("Try to automatically convert HogQL queries to use preaggregated tables at the AST level *"),
    )
    useWebAnalyticsPreAggregatedTables: bool | None = None


