class TrendsFilter(BaseModel):
    model_config = ConfigDict(
        extra="forbid",
    )
    aggregationAxisFormat: AggregationAxisFormat | None = Field(
        default=AggregationAxisFormat.NUMERIC,
        description=(
            "Y-axis value formatter. Picks a human-friendly unit per value at render"
            " time without changing the underlying series values.\n\n- `numeric`"
            " (default): raw numbers, e.g. `1,234`.\n- `duration`: values are in"
            " seconds; rendered as friendly units per value (`45s`, `2m 12s`, `1h 4m`)."
            " Use this whenever the series is in seconds (latency, session length,"
            " time-to-event) instead of dividing in `formula` to force minutes or"
            " hours.\n- `duration_ms`: values are in milliseconds; rendered as friendly"
            " units (`850ms`, `1.5s`, `1m 4s`).\n- `percentage`: values are already in"
            " the 0-100 range; appends `%`.\n- `percentage_scaled`: values are a 0-1"
            " ratio; multiplied and rendered as `%`.\n- `currency`: values are in the"
            " project's base currency (set in project settings, defaults to USD);"
            " rendered with that currency symbol. For values pinned to a specific"
            " currency regardless of project base (e.g. `$ai_total_cost_usd` is always"
            " USD), use `aggregationAxisPrefix` instead.\n- `short`: compact notation"
            " for large counts (`1.2K`, `3.4M`)."
        ),
    )
    aggregationAxisPostfix: str | None = Field(
        default=None,
        description=(
            "Literal suffix applied to every value (e.g. ` req`). Reserve for units"
            " that `aggregationAxisFormat` cannot express. Do not use ` mins`, ` s`, `"
            " ms`, `%` etc. — pick the matching `aggregationAxisFormat` instead so the"
            " underlying values stay numerically correct for breakdowns, formulas, and"
            " alerts. Include any leading space yourself."
        ),
    )
    aggregationAxisPrefix: str | None = Field(
        default=None,
        description=(
            "Literal prefix applied to every value (e.g. `$`). Use to pin a unit or"
            " currency symbol that does not depend on `aggregationAxisFormat` — for"
            " example, when values are denominated in a fixed currency regardless of"
            " the project's base currency. Include any trailing space yourself."
        ),
    )
    breakdown_histogram_bin_count: float | None = None
    chartStyle: ChartStyle | None = Field(default=None, description="Chart rendering style overrides (line shape).")
    confidenceLevel: float | None = None
    decimalPlaces: float | None = Field(
        default=None,
        description=("Maximum number of decimal places shown. 1 or 2 is usually right for percentages and currency."),
    )
    detailedResultsAggregationType: DetailedResultsAggregationType | None = Field(
        default=None, description="detailed results table"
    )
    display: ChartDisplayType | None = ChartDisplayType.ACTIONS_LINE_GRAPH
    excludeBoxPlotOutliers: bool | None = True
    formula: str | None = None
    formulaNodes: list[TrendsFormulaNode] | None = Field(
        default=None,
        description=("List of formulas with optional custom names. Takes precedence over formula/formulas if set."),
    )
    formulas: list[str] | None = None
    goalLines: list[GoalLine] | None = Field(default=None, description="Goal Lines")
    hiddenLegendIndexes: list[int] | None = None
    hideWeekends: bool | None = False
    legendPosition: LegendPosition | None = Field(
        default=LegendPosition.BOTTOM,
        description=("Where the in-chart legend sits relative to the plot. Only applies to the in-chart legend."),
    )
    metricChangeDecreaseColor: str | None = Field(
        default=None,
        description=("Metric display: change pill color when the metric decreased. Defaults to red."),
    )
    metricChangeIncreaseColor: str | None = Field(
        default=None,
        description=("Metric display: change pill color when the metric increased. Defaults to green."),
    )
    metricColorByDirection: bool | None = Field(
        default=False,
        description=("Metric display: color the sparkline by whether the metric increased or decreased."),
    )
    metricLineDecreaseColor: str | None = Field(
        default=None,
        description=("Metric display: line color when the metric decreased. Defaults to red."),
    )
    metricLineIncreaseColor: str | None = Field(
        default=None,
        description=("Metric display: line color when the metric increased. Defaults to green."),
    )
    metricShowChange: bool | None = Field(
        default=True,
        description="Show the period-over-period change pill on the Metric display.",
    )
    metricSummary: MetricSummary | None = Field(
        default=MetricSummary.TOTAL,
        description=(
            "Metric display: which summary the resting headline shows — the period"
            " total, the average, or the latest point. Hovering the sparkline always"
            " shows the hovered point's value. Also drives the change pill:"
            ' total/average compare against the previous period when "compare to'
            ' previous" is on; latest compares first→last of the series.'
        ),
    )
    minDecimalPlaces: float | None = None
    movingAverageIntervals: float | None = None
    resultCustomizationBy: ResultCustomizationBy | None = Field(
        default=ResultCustomizationBy.VALUE,
        description=("Wether result datasets are associated by their values or by their order."),
    )
    resultCustomizations: dict[str, ResultCustomizationByValue] | dict[str, ResultCustomizationByPosition] | None = (
        Field(
            default=None,
            description="Customizations for the appearance of result datasets.",
        )
    )
    showAlertThresholdLines: bool | None = False
    showAnnotations: bool | None = True
    showConfidenceIntervals: bool | None = None
    showLabelsOnSeries: bool | None = None
    showLegend: bool | None = False
    showMovingAverage: bool | None = None
    showMultipleYAxes: bool | None = False
    showPercentStackView: bool | None = False
    showTrendLines: bool | None = None
    showValuesOnSeries: bool | None = False
    smoothingIntervals: int | None = 1
    stackBreakdownValues: bool | None = Field(
        default=False,
        description=(
            "On the horizontal bar-value chart, stack a series' breakdown values into a"
            " single bar instead of rendering one bar per breakdown value."
        ),
    )
    xAxisLabel: str | None = Field(default=None, description="Custom label rendered under the X axis.")
    yAxisLabel: str | None = Field(default=None, description="Custom label rendered alongside the Y axis.")
